        std::cout << "DVD Player on.\n";
    }
};

class SoundSystem {
public:
    void on() {
        std::cout << "Sound System on.\n";
    }
};

// Facade
class HomeTheaterFacade {
    Projector projector;
    DvdPlayer dvdPlayer;
    SoundSystem soundSystem;
public:
    void watchMovie() {
        std::cout << "Get ready to watch a movie...\n";
        projector.on();
        dvdPlayer.on();
        soundSystem.on();
    }
};

int main() {
    HomeTheaterFacade homeTheater;
    homeTheater.watchMovie();
    return 0;
}

