#include <iostream>
#include <string>

// Subsystem classes

class Light {
public:
    void on() {
        std::cout << "Light is ON\n";
    }

    void off() {
        std::cout << "Light is OFF\n";
    }
};

class Thermostat {
public:
    void setTemperature(int temp) {
        std::cout << "Thermostat set to " << temp << "°C\n";
    }
};

class SecurityCamera {
public:
    void activate() {
        std::cout << "Security Camera activated\n";
    }

    void deactivate() {
        std::cout << "Security Camera deactivated\n";
    }
};

// Facade
class SmartHomeFacade {
    Light light;
    Thermostat thermostat;
    SecurityCamera camera;

public:
    void leavingHome() {
        std::cout << "\n=== Leaving Home Scenario ===\n";
        light.off();
        thermostat.setTemperature(16);  // eco mode
        camera.activate();
    }

    void arrivingHome() {
        std::cout << "\n=== Arriving Home Scenario ===\n";
        light.on();
        thermostat.setTemperature(22);  // comfortable temperature
        camera.deactivate();
    }
};

int main() {
    SmartHomeFacade smartHome;

    // Demonstrate Leaving Home scenario
    smartHome.leavingHome();

    // Demonstrate Arriving Home scenario
    smartHome.arrivingHome();

    return 0;
}

